        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specific style: brief, detailed, or bullet-points.")]
    public static ChatMessage SummarizeWithStyle(
        [Description("The content to summarize")] string content,
        [Description("Summary style: brief, detailed, or bullet-points")] string style = "brief") =>
        new(ChatRole.User,
            $"Summarize the following content using a '{style}' style:\n\n{content}");
}

